(() => {
  const key = "panel-enabled";
  const id = `${marinara.extensionId}:${encodeURIComponent(key)}`;
  let enabled = true;

  marinara.addStyle(`
    .de-koi-sample-panel {
      position: fixed;
      right: 16px;
      bottom: 16px;
      z-index: 2147483000;
      display: grid;
      gap: 8px;
      max-width: 220px;
      padding: 12px;
      border: 1px solid color-mix(in srgb, var(--border, #d9dfd5), transparent 15%);
      border-radius: 8px;
      background: var(--background, #fbfcf8);
      color: var(--foreground, #1f2a24);
      box-shadow: 0 12px 32px rgba(0, 0, 0, 0.16);
      font: 13px/1.4 system-ui, sans-serif;
    }
    .de-koi-sample-panel button {
      border: 1px solid var(--border, #d9dfd5);
      border-radius: 6px;
      background: var(--secondary, #eef2ea);
      color: inherit;
      padding: 6px 8px;
      cursor: pointer;
    }
  `);

  const panel = marinara.addElement(document.body, "aside", {
    class: "de-koi-sample-panel",
    role: "status",
    "aria-live": "polite"
  });
  if (!panel) return;

  marinara.addElement(panel, "strong", { textContent: marinara.extensionName });
  const status = marinara.addElement(panel, "span", { textContent: "Loading memory..." });
  const button = marinara.addElement(panel, "button", { type: "button", textContent: "Toggle" });

  function render() {
    if (status) status.textContent = enabled ? "Stored setting: on" : "Stored setting: off";
    if (button) button.textContent = enabled ? "Turn off" : "Turn on";
  }

  async function save() {
    const value = { enabled };
    const existing = await marinara.storage.get("plugin-memory", id);
    if (existing) {
      await marinara.storage.update("plugin-memory", id, { value, schemaVersion: 1 });
      return;
    }
    await marinara.storage.create("plugin-memory", { key, value, schemaVersion: 1 });
  }

  void (async () => {
    const existing = await marinara.storage.get("plugin-memory", id);
    if (existing && typeof existing.value === "object" && existing.value) {
      enabled = existing.value.enabled !== false;
    }
    render();
  })().catch((error) => {
    if (status) status.textContent = `Memory unavailable: ${error.message}`;
  });

  if (button) {
    marinara.on(button, "click", () => {
      enabled = !enabled;
      render();
      void save().catch((error) => {
        if (status) status.textContent = `Save failed: ${error.message}`;
      });
    });
  }

  marinara.onCleanup(() => {
    console.info(`[${marinara.extensionName}] cleaned up`);
  });
})();
